try {
	// Check for circular dependency
	if (this.isCircularDependency(hook.id, execContext)) {
		throw new CircularDependencyError(
			`Circular dependency detected: ${hook.name}`
		);
	}

	// Check max depth
	if (this.isMaxDepthExceeded(execContext)) {
		throw new MaxDepthExceededError(
			`Maximum chain depth (${MAX_CHAIN_DEPTH}) exceeded`
		);
	}

	// Evaluate conditions before proceeding
	const conditionsMet = await this.evaluateConditions(hook, execContext);
	if (!conditionsMet) {
		this.outputChannel.appendLine(
			`[HookExecutor] Conditions not met, skipping hook: ${hook.name} (${hook.id})`
		);
		return {
			hookId: hook.id,
			hookName: hook.name,
			status: "skipped",
			duration: Date.now() - startTime,
		};
	}

	// Add hook to executed set
	execContext.executedHooks.add(hook.id);
	execContext.chainDepth += 1;

	// Build template context
	// Extract trigger type from hook's trigger configuration
	const triggerOperation =
		hook.trigger?.operation || triggerEvent?.operation || "unknown";
	const templateContext = await this.buildTemplateContext(
		triggerOperation,
		undefined,
		triggerEvent
	);

	// Handle scheduling before execution
	if (hook.schedule && hook.schedule.type !== "immediate") {
		// Stub: future phases will hand off to a real scheduler service
		this.outputChannel.appendLine(
			`[HookExecutor] Hook ${hook.name} scheduled for ${hook.schedule.type} execution. (Scheduler stub)`
		);

		// For now, if delayed, we wait
		if (hook.schedule.type === "delayed" && hook.schedule.delayMs) {
			this.outputChannel.appendLine(`[HookExecutor] Delaying execution by ${hook.schedule.delayMs}ms`);
			await new Promise(resolve => setTimeout(resolve, hook.schedule.delayMs));
		} else {
			return {
				hookId: hook.id,
				hookName: hook.name,
				status: "skipped",
				duration: Date.now() - startTime,
			};
		}
	}

	// Emit execution started event

